fixed_code:
predicate IsDigit(c: char)
{
    48 <= c as int <= 57
}

method IsIntegerString(s: string) returns (result: bool)
    ensures result == ((|s| > 0 && (s[0] == '-' || s[0] == '+') && |s| > 1 && (forall j: int :: 1 <= j < |s| ==> IsDigit(s[j]))) || (|s| > 0 && (forall j: int :: 0 <= j < |s| ==> IsDigit(s[j]))))
{
    if |s| == 0 {
        result := false;
        return;
    }

    var startIndex := 0;
    if s[0] == '-' || s[0] == '+' {
        if |s| == 1 {
            result := false;
            return;
        }
        startIndex := 1;
    }

    var allDigits := true;
    var i := startIndex;
    while i < |s|
        invariant startIndex <= i <= |s|
        invariant allDigits ==> (forall j: int :: startIndex <= j < i ==> IsDigit(s[j]))
        invariant (forall j: int :: startIndex <= j < i ==> IsDigit(s[j]))
    {
        if !IsDigit(s[i]) {
            allDigits := false;
            break;
        }
        i := i + 1;
    }
    result := allDigits;
    assert result == (forall j: int :: startIndex <= j < |s| ==> IsDigit(s[j]));
}
